def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 1.0
        adjustment = 1.0
        penalty = 0.0
        decay = 1.0
        cumprod = 1.0
        for j in range(1, 15):
            if j % 4 == 0:
                decay *= 0.98 + 0.005 * j
            elif j % 6 == 0:
                decay *= 1.02 - 0.003 * j
            weight = np.tanh(ratio * j) * (j ** 1.5)
            if cap % (j + 2) == 0:
                score += (weight / (j + 1)) * decay
            else:
                score -= (np.log1p(weight) + np.sin(ratio*j)) * decay / (j + 2)
            if (cap + j*j*j) % 11 == 0:
                penalty += np.cos(j*ratio) * 0.7
            elif (cap*j*j) % 13 == 0:
                penalty -= np.exp(-j/10) * 0.6
            if j == 7:
                for k in range(1, 8):
                    diff = cap - item * (k ** 3)
                    abs_diff = abs(diff)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            penalty += (abs_diff ** 0.6) / (k + 4)
                        else:
                            penalty -= np.log1p(abs_diff) / (k + 5)
                    else:
                        penalty -= (abs_diff ** 1.5) / (k + 2)
            if ratio > 0.9 and j % 2 == 1:
                adjustment *= 1.12 + 0.015 * j
            elif ratio < 0.15 and j % 5 == 0:
                adjustment *= 0.85 - 0.02 * j
            if j % 3 == 2 and cap % (j + 3) == 0:
                penalty += np.sin(j * ratio * 1.5) * 0.4
            cumprod *= (1 + 0.01 * (-1)**j * j)
        score = score * adjustment + penalty * 0.75
        score *= cumprod
        if score <= 0:
            priorities[i] = -score * (np.sqrt(cap + item) + np.cbrt(cap))
        else:
            if cap > item * 5:
                factor = 1 + np.log1p(ratio * cap)
                priorities[i] = -score / (np.sqrt(cap) + 2) * factor
            else:
                priorities[i] = -score / (cap + 5) * np.exp(-ratio**3)
        if ratio > 0.98:
            priorities[i] *= 1.18
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.95
        elif cap % 5 == 0:
            priorities[i] *= 1.05
    return priorities
